import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    if len(unvisited_customers) == 0:
        return None  # No customers left to visit, might need to rest or end the route

    distances = np.linalg.norm(unvisited_customers - cur_truck_pos, axis=1)
    distance_to_depot = np.linalg.norm(unvisited_customers - depot_pos, axis=1)
    congestion_penalties = np.zeros(len(unvisited_customers))

    # Assess how many trucks are closer to each customer than the current truck
    for i, customer_pos in enumerate(unvisited_customers):
        for other_truck_pos in all_truck_pos:
            if not np.array_equal(other_truck_pos, cur_truck_pos):
                if np.linalg.norm(customer_pos - other_truck_pos) < distances[i]:
                    congestion_penalties[i] += 1

    # Scoring function that increases priority for nearby customers and those less visited by other trucks
    scores = distances + 0.5 * congestion_penalties + 0.2 * distance_to_depot

    best_node = None
    min_score = np.inf

    for idx, score in enumerate(scores):
        if score < min_score:
            min_score = score
            best_node = idx

    return best_node
